function activate(context) {
  context.ui.addToolbarButton({
    icon: 'list',
    label: context.t('toolbar.label'),
    onClick: function () {
      var files = context.files.getAll();
      var hits = [];
      for (var i = 0; i < files.length; i++) {
        var f = files[i];
        var lines = f.content.split(/\r?\n/);
        for (var j = 0; j < lines.length; j++) {
          var line = lines[j];
          if (/\b(TODO|FIXME|HACK)\b/i.test(line)) {
            hits.push(f.name + ':' + (j + 1) + ' ' + line.trim().slice(0, 100));
          }
        }
      }
      var body = hits.length ? hits.slice(0, 50).join('\n') : context.t('notify.empty');
      context.ui.showModal(context.t('modal.title'), body);
    },
  });
}
